@import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700;800;900&display=swap');

@tailwind base;
@tailwind components;
@tailwind utilities;

/* Force scrollbar to always be present to prevent layout shifts */
html {
  overflow-y: scroll !important;
  scrollbar-gutter: stable;
}

body {
  overflow-x: hidden !important;
  width: 100vw !important;
  position: relative;
}

/* Completely isolate dropdown content from page layout */
[data-radix-select-content] {
  position: fixed !important;
  z-index: 9999 !important;
  transform: translateZ(0) !important; /* Force hardware acceleration */
  contain: layout style paint !important; /* Isolate from document flow */
}

/* Prevent any layout reflow during dropdown interactions */
[data-radix-select-trigger] {
  contain: layout !important;
}

/* Create stacking context to isolate filters */
.filters-section {
  isolation: isolate;
  contain: layout style;
}

/* Hero Section Backgrounds with Image Management System IDs */
/* ID-831: About page hero - Industrial automation facility background */
.hero-bg-about {
  background-image: url('data:image/svg+xml;base64,');
  background-size: cover;
  background-position: center;
  background-repeat: no-repeat;
}

/* ID-832: Services page hero - Process automation systems background */
.hero-bg-services {
  background-image: url('data:image/svg+xml;base64,');
  background-size: cover;
  background-position: center;
  background-repeat: no-repeat;
}

/* ID-833: Products page hero - Industrial equipment showcase background */
.hero-bg-products {
  background-image: url('data:image/svg+xml;base64,');
  background-size: cover;
  background-position: center;
  background-repeat: no-repeat;
}

/* ID-834: Projects page hero - Power plant construction background */
.hero-bg-projects {
  background-image: url('data:image/svg+xml;base64,');
  background-size: cover;
  background-position: center;
  background-repeat: no-repeat;
}

/* ID-835: Contact page hero - Professional office meeting background */
.hero-bg-contact {
  background-image: url('data:image/svg+xml;base64,');
  background-size: cover;
  background-position: center;
  background-repeat: no-repeat;
}

/* ID-836: News page hero - Modern office environment background */
.hero-bg-news {
  background-image: url('data:image/svg+xml;base64,');
  background-size: cover;
  background-position: center;
  background-repeat: no-repeat;
}

/* ID-837: Instrumentation components hero - Measurement instruments background */
.hero-bg-instrumentation {
  background-image: url('data:image/svg+xml;base64,');
  background-size: cover;
  background-position: center;
  background-repeat: no-repeat;
}

/* Theme-Aware Professional Hero Backgrounds */
/* Modern CSS-based backgrounds that adapt to light/dark themes */
.hero-bg-about-v2 {
  background: linear-gradient(135deg, rgb(30, 64, 175) 0%, rgb(54, 99, 181) 50%, rgb(73, 123, 191) 100%);
  background-size: cover;
  background-position: center;
  background-repeat: no-repeat;
}

/* Dark mode variants */
@media (prefers-color-scheme: dark) {
  .hero-bg-about-v2 {
    background: linear-gradient(135deg, rgb(30, 64, 175, 0.85) 0%, rgb(54, 99, 181, 0.85) 50%, rgb(73, 123, 191, 0.85) 100%);
  }
}

[data-theme="dark"] .hero-bg-about-v2 {
  background: linear-gradient(135deg, rgb(30, 64, 175, 0.85) 0%, rgb(54, 99, 181, 0.85) 50%, rgb(73, 123, 191, 0.85) 100%);
}

/* Theme-aware overlay patterns */
.hero-pattern-light {
  background-image: 
    radial-gradient(circle at 25% 25%, rgba(59, 130, 246, 0.3) 1px, transparent 1px),
    radial-gradient(circle at 75% 75%, rgba(16, 185, 129, 0.3) 1px, transparent 1px);
  background-size: 50px 50px, 50px 50px;
  background-position: 0 0, 25px 25px;
  opacity: 0.2;
}

.hero-pattern-dark {
  background-image: 
    radial-gradient(circle at 25% 25%, rgba(59, 130, 246, 0.2) 1px, transparent 1px),
    radial-gradient(circle at 75% 75%, rgba(16, 185, 129, 0.2) 1px, transparent 1px);
  background-size: 50px 50px, 50px 50px;
  background-position: 0 0, 25px 25px;
  opacity: 0.1;
}

/* Full Screen Hero Sections */
.hero-fullscreen {
  width: 100vw;
  height: calc(100vh - 80px); /* Subtract header height */
  min-height: 500px;
  display: flex;
  align-items: center;
  justify-content: center;
}

/* Mobile sidebar body scroll lock - More specific targeting */
body.sidebar-open {
  overflow: hidden !important;
  position: fixed !important;
  width: 100% !important;
  height: 100% !important;
}

/* Hide main page scrollbars when sidebar is open */
body.sidebar-open::-webkit-scrollbar {
  display: none !important;
}

body.sidebar-open {
  -ms-overflow-style: none !important;
  scrollbar-width: none !important;
}

/* Lock main content only, not modal/sheet content */
#root.sidebar-open {
  overflow: hidden !important;
  position: fixed !important;
  top: 0 !important;
  left: 0 !important;
  right: 0 !important;
  bottom: 0 !important;
}

/* Allow sheets and dialogs to scroll when sidebar is open */
body.sidebar-open [data-radix-dialog-content],
body.sidebar-open [data-radix-sheet-content] {
  overflow-y: auto !important;
  position: relative !important;
  height: 100vh !important;
}

:root {
  --background: hsl(0, 0%, 100%);
  --foreground: hsl(210, 25%, 7%);
  --card: hsl(0, 0%, 100%);
  --card-foreground: hsl(210, 25%, 7%);
  --popover: hsl(0, 0%, 100%);
  --popover-foreground: hsl(210, 25%, 7%);
  --primary: hsl(215, 89%, 33%);
  --primary-foreground: hsl(0, 0%, 100%);
  --secondary: hsl(20, 91%, 48%);
  --secondary-foreground: hsl(0, 0%, 100%);
  --muted: hsl(210, 40%, 98%);
  --muted-foreground: hsl(210, 8%, 45%);
  --accent: hsl(215, 89%, 59%);
  --accent-foreground: hsl(0, 0%, 100%);
  --destructive: hsl(0, 84%, 60%);
  --destructive-foreground: hsl(0, 0%, 100%);
  --border: hsl(214, 32%, 91%);
  --input: hsl(214, 32%, 91%);
  --ring: hsl(215, 89%, 33%);
  --chart-1: hsl(215, 89%, 33%);
  --chart-2: hsl(160, 60%, 45%);
  --chart-3: hsl(30, 80%, 55%);
  --chart-4: hsl(280, 65%, 60%);
  --chart-5: hsl(340, 75%, 55%);
  --sidebar: hsl(0, 0%, 100%);
  --sidebar-foreground: hsl(210, 25%, 7%);
  --sidebar-primary: hsl(215, 89%, 33%);
  --sidebar-primary-foreground: hsl(0, 0%, 100%);
  --sidebar-accent: hsl(210, 40%, 98%);
  --sidebar-accent-foreground: hsl(215, 89%, 33%);
  --sidebar-border: hsl(214, 32%, 91%);
  --sidebar-ring: hsl(215, 89%, 33%);
  --font-sans: 'Inter', system-ui, sans-serif;
  --font-serif: 'Georgia', serif;
  --font-mono: 'Menlo', monospace;
  --radius: 0.5rem;
}

.dark {
  --background: hsl(220, 25%, 8%);
  --foreground: hsl(210, 40%, 95%);
  --card: hsl(220, 25%, 12%);
  --card-foreground: hsl(210, 40%, 95%);
  --popover: hsl(220, 25%, 12%);
  --popover-foreground: hsl(210, 40%, 95%);
  --primary: hsl(215, 89%, 55%);
  --primary-foreground: hsl(0, 0%, 100%);
  --secondary: hsl(20, 91%, 55%);
  --secondary-foreground: hsl(0, 0%, 100%);
  --muted: hsl(220, 25%, 18%);
