      {/* Main Content with Tabs */}
      <section className="py-12 bg-background">
        <div className="max-w-7xl mx-auto px-4 md:px-6 lg:px-8">
          <div className="text-center mb-12">
            <h2 className="text-3xl md:text-4xl font-bold text-foreground mb-6">
              Our Project Portfolio
            </h2>
            <p className="text-xl text-muted-foreground max-w-3xl mx-auto">
              From power generation to manufacturing automation, explore how we've delivered innovative engineering solutions across various industries.
            </p>
          </div>

          <Tabs value={selectedTab} onValueChange={setSelectedTab} className="w-full">
            <TabsList className="grid w-full grid-cols-2 max-w-md mx-auto mb-8">
              <TabsTrigger value="portfolio">Project Portfolio</TabsTrigger>
              <TabsTrigger value="showcase">Featured Projects</TabsTrigger>
            </TabsList>

            <TabsContent value="portfolio" className="space-y-8">
              {/* Search and Filters */}
              <div className="space-y-6 filters-section">
                {/* Search Bar */}
                <div className="max-w-md mx-auto">
                  <div className="relative">
                    <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-muted-foreground w-5 h-5" />
                    <Input
                      placeholder="Search projects, clients, or technologies..."
                      value={searchTerm}
                      onChange={(e) => setSearchTerm(e.target.value)}
                      className="pl-10"
                    />
                  </div>
                </div>

                {/* Filter Toggle */}
                <div className="text-center">
                  <Button 
                    variant="outline" 
                    onClick={() => setShowFilters(!showFilters)}
                    className={`border-2 border-primary text-primary hover:bg-primary hover:text-primary-foreground transition-all duration-300 ${
                      showFilters ? 'bg-primary/10' : ''
                    }`}
                  >
                    <Filter className={`mr-2 w-4 h-4 transition-transform duration-300 ${showFilters ? 'rotate-180' : ''}`} />
                    {showFilters ? 'Hide Filters' : 'Show Filters'}
                  </Button>
                </div>

                {/* Filters */}
                <div className="overflow-hidden">
                  <div className={`transition-all duration-300 ease-in-out ${
                    showFilters 
                      ? 'max-h-96 opacity-100 translate-y-0' 
                      : 'max-h-0 opacity-0 -translate-y-4'
                  }`}>
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-4 p-6 bg-muted/50 backdrop-blur-sm rounded-lg border border-border/20 mt-4" style={{contain: 'layout style'}}>  
                      <div className="min-w-0">
                        <label className="text-sm font-medium mb-2 block">Industry</label>
                        <Select value={selectedIndustry} onValueChange={setSelectedIndustry}>
                          <SelectTrigger className="w-full">
                            <SelectValue placeholder="Select Industry" />
                          </SelectTrigger>
                          <SelectContent>
                            {INDUSTRIES.map(industry => (
                              <SelectItem key={industry} value={industry}>{industry}</SelectItem>
                            ))}
