                            </div>
                          </div>
                        )}

                        {/* Step 4: Additional Information */}
                        {currentStep === 4 && (
                          <>
                            <div>
                              <Label htmlFor="location" className="text-sm font-medium mb-2 block">Project Location</Label>
                              <Input
                                id="location"
                                placeholder="City, State"
