import React, { useState, useEffect } from "react";
import { Link, useLocation } from "wouter";
import { Button } from "@/components/ui/button";
import {
  Sheet,
  SheetContent,
  SheetTrigger,
  SheetTitle,
  SheetDescription,
} from "@/components/ui/sheet";
import { Menu, Phone, Mail, MapPin, ChevronDown } from "lucide-react";
import { COMPANY_INFO, SERVICES, PRODUCTS } from "@/data/constants";
import { motion, AnimatePresence } from "framer-motion";
import logoImage from "@assets/mainlogopowerton (1)_1755674514195.png";

export default function Header() {
  const [location] = useLocation();
  const [isOpen, setIsOpen] = useState(false);
  const [isMobileServicesOpen, setIsMobileServicesOpen] = useState(false);
  const [isMobileProductsOpen, setIsMobileProductsOpen] = useState(false);
  const [isProductsDropdownOpen, setIsProductsDropdownOpen] = useState(false);
  const [headerHeight, setHeaderHeight] = useState(100);

  // Hide body scrollbar when mobile sidebar is open
  useEffect(() => {
    const rootElement = document.getElementById("root");

    if (isOpen) {
      document.body.classList.add("sidebar-open");
      document.documentElement.classList.add("sidebar-open");
      if (rootElement) rootElement.classList.add("sidebar-open");
    } else {
      document.body.classList.remove("sidebar-open");
      document.documentElement.classList.remove("sidebar-open");
      if (rootElement) rootElement.classList.remove("sidebar-open");
    }

    // Cleanup function to restore scrollbar when component unmounts
    return () => {
      document.body.classList.remove("sidebar-open");
      document.documentElement.classList.remove("sidebar-open");
      if (rootElement) rootElement.classList.remove("sidebar-open");
    };
  }, [isOpen]);

  // Handle click outside to close products dropdown
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      const target = event.target as Element;
      if (!target.closest('.products-dropdown-container')) {
        setIsProductsDropdownOpen(false);
      }
    };

    if (isProductsDropdownOpen) {
      document.addEventListener('mousedown', handleClickOutside);
    }

    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, [isProductsDropdownOpen]);

  // Calculate header height for dropdown positioning
  useEffect(() => {
    const updateHeaderHeight = () => {
      const header = document.querySelector('header[role="banner"]');
      if (header) {
        setHeaderHeight((header as HTMLElement).offsetHeight);
      }
    };

    updateHeaderHeight();
    window.addEventListener('resize', updateHeaderHeight);

    return () => {
      window.removeEventListener('resize', updateHeaderHeight);
    };
  }, []);

  const navigation = [
    { name: "About", href: "/about" },
    { name: "Projects", href: "/projects" },
    { name: "Gallery", href: "/gallery" },
    { name: "News & Updates", href: "/news" },
    { name: "Contact", href: "/contact" },
  ];

  const isActive = (href: string) => {
    if (href === "/" && location === "/") return true;
    if (href !== "/" && href !== "#" && location.startsWith(href)) return true;
    return false;
  };

  return (
    <header
      className="bg-background border-b border-border shadow-sm sticky top-0 z-50"
      role="banner"
    >
      {/* Top bar */}
      <motion.div
        className="bg-primary text-white py-1 sm:py-2 header-top-bar"
        initial={{ opacity: 0, y: -20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.5, ease: [0.25, 0.46, 0.45, 0.94] }}
      >
        <div className="max-w-7xl mx-auto px-2 sm:px-4 md:px-6 lg:px-8 flex flex-col sm:flex-row sm:justify-between items-center gap-3 sm:gap-0 text-xs sm:text-sm py-1">
          <motion.div
            className="flex items-center gap-3 sm:gap-4 flex-wrap justify-center sm:justify-start w-full sm:w-auto"
            initial="hidden"
            animate="visible"
            variants={{
              hidden: {},
              visible: {
                transition: {
                  staggerChildren: 0.1,
                  delayChildren: 0.2,
                },
              },
            }}
          >
            <motion.a
              href={`tel:${COMPANY_INFO.phone}`}
              className="flex items-center hover:text-secondary transition-colors hover-scale shrink-0"
              aria-label="Call us"
              variants={{
                hidden: { opacity: 0, x: -20 },
                visible: { opacity: 1, x: 0 },
              }}
              whileHover={{ scale: 1.05 }}
              transition={{ duration: 0.2 }}
            >
              <Phone
                className="w-3 h-3 sm:w-4 sm:h-4 mr-1 text-secondary shrink-0"
                aria-hidden="true"
              />
              <span className="hidden sm:inline whitespace-nowrap">
                {COMPANY_INFO.phone}
              </span>
              <span className="sm:hidden">Call</span>
            </motion.a>
            <motion.a
              href={`mailto:${COMPANY_INFO.email}`}
              className="flex items-center hover:text-secondary transition-colors hover-scale shrink-0"
              aria-label="Email us"
              variants={{
                hidden: { opacity: 0, x: -20 },
                visible: { opacity: 1, x: 0 },
              }}
              whileHover={{ scale: 1.05 }}
              transition={{ duration: 0.2 }}
            >
              <Mail
                className="w-3 h-3 sm:w-4 sm:h-4 mr-1 text-secondary shrink-0"
                aria-hidden="true"
              />
              <span className="hidden md:inline whitespace-nowrap text-xs md:text-sm">
                {COMPANY_INFO.email}
              </span>
              <span className="md:hidden">Email</span>
            </motion.a>
          </motion.div>
          <motion.a
            href="https://maps.app.goo.gl/jiap3sBYbM3r8Pn68"
            target="_blank"
            rel="noopener noreferrer"
            className="hidden md:flex items-center hover:text-secondary transition-colors cursor-pointer hover-scale"
            aria-label="Open office location in Google Maps"
            initial={{ opacity: 0, x: 20 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ duration: 0.6, delay: 0.3 }}
            whileHover={{ scale: 1.05 }}
          >
            <span className="flex items-center">
              <MapPin
                className="w-4 h-4 mr-2 text-secondary"
                aria-hidden="true"
              />
              <span className="text-xs lg:text-sm">
                {COMPANY_INFO.address.city}, {COMPANY_INFO.address.state} -
                Serving All India
              </span>
            </span>
          </motion.a>
        </div>
      </motion.div>

      {/* Main navigation */}
      <nav
        className="max-w-7xl mx-auto px-2 md:px-4 lg:px-6 xl:px-8"
        role="navigation"
        aria-label="Main navigation"
      >
        <div className="flex justify-between items-center py-3 sm:py-4">
          <motion.div
            initial={{ opacity: 0, x: -30 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ duration: 0.6, delay: 0.2 }}
          >
            <Link href="/" className="flex items-center ml-2 lg:ml-4">
              <div className="relative w-[140px] sm:w-[160px] md:w-[180px] lg:w-[200px] xl:w-[220px] h-8 sm:h-10 md:h-12 lg:h-13 xl:h-14 overflow-hidden mr-4 lg:mr-6 xl:mr-8">
                <img
                  src={logoImage}
                  alt="ID-001: Powerton Engineering Pvt. Ltd. logo"
                  className="absolute inset-0 w-full h-full object-contain"
                  loading="eager"
                />
              </div>
            </Link>
          </motion.div>

          {/* Desktop navigation */}
          <motion.div
            className="hidden lg:flex items-center space-x-4 xl:space-x-6 2xl:space-x-8"
            initial={{ opacity: 0, y: -20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6, delay: 0.3 }}
          >
            {navigation.map((item, index) => {
              if (item.name === "About") {
                return (
                  <React.Fragment key={item.name}>
                    <motion.div
                      initial={{ opacity: 0, y: -20 }}
                      animate={{ opacity: 1, y: 0 }}
                      transition={{ duration: 0.4, delay: 0.4 + index * 0.1 }}
                    >
                      <Link
                        href={item.href}
                        className={`text-foreground hover:text-primary transition-colors font-medium relative whitespace-nowrap ${
                          isActive(item.href) ? "text-primary" : ""
                        }`}
                      >
                        <motion.span
                          whileHover={{ y: -2 }}
                          transition={{ duration: 0.2 }}
                        >
                          {item.name}
                        </motion.span>
                        {isActive(item.href) && (
                          <motion.div
                            className="absolute -bottom-1 left-0 right-0 h-0.5 bg-primary"
                            layoutId="activeNav"
                            initial={{ opacity: 0, scaleX: 0 }}
                            animate={{ opacity: 1, scaleX: 1 }}
                            transition={{ duration: 0.3 }}
                          />
                        )}
                      </Link>
                    </motion.div>

                    {/* Services Dropdown */}
                    <motion.div
                      initial={{ opacity: 0, y: -20 }}
                      animate={{ opacity: 1, y: 0 }}
                      transition={{
                        duration: 0.4,
                        delay: 0.4 + (index + 1) * 0.1,
                      }}
                      className="relative group"
                    >
                      <div
                        className={`text-foreground hover:text-primary transition-colors font-medium relative flex items-center gap-1 cursor-pointer ${
                          isActive("/services") ? "text-primary" : ""
                        }`}
                      >
                        <Link href="/services" className="hover:text-primary">
                          Services
                        </Link>
                        <ChevronDown className="h-4 w-4" />
                        {isActive("/services") && (
                          <motion.div
                            className="absolute -bottom-1 left-0 right-0 h-0.5 bg-primary"
                            layoutId="activeNav"
                            initial={{ opacity: 0, scaleX: 0 }}
                            animate={{ opacity: 1, scaleX: 1 }}
                            transition={{ duration: 0.3 }}
                          />
                        )}
                      </div>

                      {/* Hover Dropdown Content */}
                      <div className="fixed left-1/2 -translate-x-1/2 w-max max-w-[95vw] max-h-[90vh] bg-popover border border-border rounded-md shadow-lg opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all duration-200 z-50 overflow-y-auto" style={{top: `calc(${headerHeight}px - 1rem)`}}>
                        <div className="p-6 lg:p-8">
                          <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-6 lg:gap-8 items-stretch">
                            {SERVICES.map((service) => (
                              <Link
                                key={service.id}
                                href={`/services/${service.id}`}
                                className="block px-4 py-4 lg:py-6 rounded-sm hover:bg-accent hover:text-accent-foreground cursor-pointer transition-colors border border-border/50 min-w-0 min-h-[120px] lg:min-h-[140px]"
                              >
                                <div className="flex flex-col h-full justify-between">
                                  <div className="font-semibold text-foreground text-sm lg:text-base line-clamp-2 mb-2">
                                    {service.title}
                                  </div>
                                  <div className="text-xs lg:text-sm text-muted-foreground line-clamp-3 mt-auto">
                                    {service.description.slice(0, 80)}...
                                  </div>
                                </div>
                              </Link>
                            ))}
                          </div>
                        </div>
                      </div>
                    </motion.div>

                    {/* Products Dropdown */}
                    <motion.div
                      initial={{ opacity: 0, y: -20 }}
                      animate={{ opacity: 1, y: 0 }}
                      transition={{
                        duration: 0.4,
                        delay: 0.5 + (index + 1) * 0.1,
                      }}
                      className="relative products-dropdown-container"
                    >
                      <div
                        className={`text-foreground hover:text-primary transition-colors font-medium relative flex items-center gap-1 cursor-pointer ${
                          isActive("/products") ? "text-primary" : ""
                        }`}
                        onMouseEnter={() => setIsProductsDropdownOpen(true)}
                        onMouseLeave={() => setIsProductsDropdownOpen(false)}
                        onClick={() => setIsProductsDropdownOpen(!isProductsDropdownOpen)}
                      >
                        <Link href="/products" className="hover:text-primary">
                          Products
                        </Link>
                        <ChevronDown className="h-4 w-4" />
                        {isActive("/products") && (
                          <motion.div
                            className="absolute -bottom-1 left-0 right-0 h-0.5 bg-primary"
                            layoutId="activeNav"
                            initial={{ opacity: 0, scaleX: 0 }}
                            animate={{ opacity: 1, scaleX: 1 }}
                            transition={{ duration: 0.3 }}
                          />
                        )}
                      </div>

                      {/* Dropdown Content */}
                      <div 
                        className={`transition-all duration-200 fixed left-1/2 -translate-x-1/2 z-50 ${
                          isProductsDropdownOpen ? 'opacity-100 visible' : 'opacity-0 invisible'
                        }`} 
                        style={{top: `calc(${headerHeight}px - 1rem)`}}
                        onMouseEnter={() => setIsProductsDropdownOpen(true)}
                        onMouseLeave={() => setIsProductsDropdownOpen(false)}
                      >
                        <div className="w-max max-w-[95vw] max-h-[70vh] bg-popover border border-border rounded-md shadow-lg overflow-y-auto">
                          <div className="p-4 lg:p-6">
                            <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 2xl:grid-cols-5 gap-3 lg:gap-4 max-w-none">
                              {PRODUCTS.map((product) => (
                                <div
                                  key={product.id}
                                  className="min-w-0 flex-shrink-0"
                                >
                                  <Link
                                    href={`/products/${product.id}`}
                                    className="block px-3 lg:px-4 py-2 lg:py-3 rounded-md hover:bg-accent hover:text-accent-foreground cursor-pointer transition-colors border border-border/50 mb-2"
                                    onClick={() => setIsProductsDropdownOpen(false)}
                                  >
                                    <div className="font-semibold text-foreground text-sm lg:text-base line-clamp-2">
                                      {product.title}
                                    </div>
                                  </Link>

                                  {/* Show subcategories for products that have them */}
                                  {product.subcategories && (
                                    <div className="ml-2 lg:ml-4 space-y-1">
                                      {product.subcategories.map((subcategory) => (
                                        <Link
                                          key={subcategory.id}
                                          href={`/products/${subcategory.id}`}
                                          className="block px-2 lg:px-3 py-1 lg:py-2 rounded-sm hover:bg-muted hover:text-foreground cursor-pointer transition-colors text-xs lg:text-sm border-l-2 border-secondary/30 hover:border-secondary"
                                          onClick={() => setIsProductsDropdownOpen(false)}
                                        >
                                          <div className="font-medium text-foreground line-clamp-1">
                                            {subcategory.title}
                                          </div>
                                        </Link>
                                      ))}
                                    </div>
                                  )}
                                </div>
                              ))}
                            </div>
                          </div>
                        </div>
                      </div>
                    </motion.div>
                  </React.Fragment>
                );
              }

              return (
                <motion.div
                  key={item.name}
                  initial={{ opacity: 0, y: -20 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ duration: 0.4, delay: 0.4 + (index + 1) * 0.1 }}
                >
                  <Link
                    href={item.href}
                    className={`text-foreground hover:text-primary transition-colors font-medium relative whitespace-nowrap ${
                      isActive(item.href) ? "text-primary" : ""
                    }`}
                  >
                    <motion.span
                      whileHover={{ y: -2 }}
                      transition={{ duration: 0.2 }}
                    >
                      <span className="xl:hidden">
                        {item.name === "News & Updates" ? "News" : item.name}
                      </span>
                      <span className="hidden xl:inline">
                        {item.name}
                      </span>
                    </motion.span>
                    {isActive(item.href) && (
                      <motion.div
                        className="absolute -bottom-1 left-0 right-0 h-0.5 bg-primary"
                        layoutId="activeNav"
                        initial={{ opacity: 0, scaleX: 0 }}
                        animate={{ opacity: 1, scaleX: 1 }}
                        transition={{ duration: 0.3 }}
                      />
                    )}
                  </Link>
                </motion.div>
              );
            })}
            <motion.div
              initial={{ opacity: 0, scale: 0.8 }}
              animate={{ opacity: 1, scale: 1 }}
              transition={{ duration: 0.4, delay: 0.8 }}
              className="ml-2"
            >
              <Link href="/quote">
                <Button className="btn-secondary hover-lift px-4 lg:px-6">Get Quote</Button>
