client/src/components/sections/clients-s.content:
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { TESTIMONIALS, CLIENTS, CLIENT_LOGOS } from "@/data/constants";
import { Star, ChevronLeft, ChevronRight } from "lucide-react";
import { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";

export default function ClientsSection() {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isAutoPlaying, setIsAutoPlaying] = useState(true);
  const [logoCurrentIndex, setLogoCurrentIndex] = useState(0);

  // Auto-slide functionality for testimonials
  useEffect(() => {
    if (!isAutoPlaying) return;

    const interval = setInterval(() => {
      try {
        setCurrentIndex((prevIndex) =>
          prevIndex === TESTIMONIALS.length - 1 ? 0 : prevIndex + 1,
        );
      } catch (error) {
        console.log('Testimonial auto-slide handled gracefully:', error);
        clearInterval(interval);
      }
    }, 4000); // Change testimonial every 4 seconds

    return () => {
      try {
        clearInterval(interval);
      } catch (error) {
        console.log('Clearing testimonial interval handled gracefully:', error);
      }
    };
  }, [isAutoPlaying]);

  // Infinite scroll - continuous without pause
  const [scrollPosition, setScrollPosition] = useState(0);
  const [isHovered, setIsHovered] = useState(false);

  useEffect(() => {
    if (isHovered) return;

    // Card width (130px) + margins (16px left + 16px right) = 162px total per card
    const cardTotalWidth = 162;

    // Smooth continuous scrolling - no pause
    const scrollInterval = setInterval(() => {
      try {
        setScrollPosition(prev => {
          const newPos = prev + 2; // Same scroll speed as before
          // Reset position when we've scrolled through first set of clients
          if (newPos >= CLIENT_LOGOS.length * cardTotalWidth) {
            return 0;
          }
          return newPos;
        });
      } catch (error) {
        console.log('Logo scroll handled gracefully:', error);
        clearInterval(scrollInterval);
      }
    }, 50); // 50ms updates but continuous

    return () => {
      try {
        clearInterval(scrollInterval);
      } catch (error) {
        console.log('Clearing scroll interval handled gracefully:', error);
      }
    };
  }, [isHovered]);

  const goToPrevious = () => {
    setIsAutoPlaying(false);
    setCurrentIndex(
      currentIndex === 0 ? TESTIMONIALS.length - 1 : currentIndex - 1,
    );
    // Resume auto-play after 8 seconds
    setTimeout(() => {
      try {
        setIsAutoPlaying(true);
      } catch (error) {
        console.log('Previous button auto-play resume handled gracefully:', error);
      }
    }, 8000);
  };

  const goToNext = () => {
    setIsAutoPlaying(false);
    setCurrentIndex(
      currentIndex === TESTIMONIALS.length - 1 ? 0 : currentIndex + 1,
    );
    // Resume auto-play after 8 seconds
    setTimeout(() => {
      try {
        setIsAutoPlaying(true);
      } catch (error) {
        console.log('Next button auto-play resume handled gracefully:', error);
      }
    }, 8000);
  };

  return (
    <section className="py-12 md:py-16 lg:py-20 bg-background" role="main">
      <div className="max-w-7xl mx-auto px-4 md:px-6 lg:px-8">
        <div className="text-center mb-16">
          <span className="text-secondary font-semibold text-lg">
            Our Clients
          </span>
          <h2 className="text-2xl sm:text-3xl lg:text-5xl font-bold text-primary mt-4 mb-6">
            Trusted By Leading Brands and Organizations
          </h2>
          <p className="text-base sm:text-lg lg:text-xl text-muted-foreground max-w-3xl mx-auto">
            We've partnered with industry leaders across various sectors to
            deliver exceptional engineering solutions.
          </p>
        </div>

        {/* Client Logos Slideshow - Continuous infinite scroll */}
        <div className="mb-16">
          <div 
            className="relative overflow-hidden bg-muted rounded-lg border border-border py-4 md:py-6 lg:py-8"
            onMouseEnter={() => setIsHovered(true)}
            onMouseLeave={() => setIsHovered(false)}
          >
            <div 
              className="flex transition-transform ease-linear"
              style={{
                transform: `translateX(-${scrollPosition}px)`,
                width: `${CLIENT_LOGOS.length * 2 * 162}px`, // Double width for seamless loop (162px per card)
              }}
            >
              {/* Render clients twice for seamless infinite loop */}
              {[...CLIENT_LOGOS, ...CLIENT_LOGOS].map((client, index) => (
                <div
                  key={`${client.id}-${Math.floor(index / CLIENT_LOGOS.length)}`}
                  className="flex-shrink-0 bg-card rounded-lg border border-border p-2 md:p-3 lg:p-4 flex items-center justify-center hover:shadow-lg transition-all duration-300 mx-2 md:mx-3 lg:mx-4"
                  style={{
                    width: "130px",
                    minWidth: "130px",
                  }}

                >
                  <div className="text-center w-full">
                    <img
                      src={client.logo}
                      alt={`ID-820-${index}: ${client.name} company logo`}
                      className="w-full h-8 md:h-10 lg:h-12 object-contain mb-1"
                      loading="lazy"
                      onError={(e) => {
                        const target = e.target as HTMLImageElement;
                        target.src = client.fallback;
                      }}
                    />
                    <span className="text-xs md:text-xs lg:text-sm font-medium text-muted-foreground block truncate">
                      {client.name}
                    </span>
                  </div>
                </div>
              ))}
            </div>



            {/* Responsive gradient overlays */}
            <div className="absolute top-0 left-0 w-8 md:w-12 lg:w-16 h-full bg-gradient-to-r from-muted to-transparent pointer-events-none z-10"></div>
            <div className="absolute top-0 right-0 w-8 md:w-12 lg:w-16 h-full bg-gradient-to-l from-muted to-transparent pointer-events-none z-10"></div>
          </div>


        </div>

        {/* Testimonials Carousel Section */}
        <div className="text-center mb-12">
          <h3 className="text-2xl font-bold text-primary mb-8">
            What Our Clients Say
          </h3>
        </div>

        <div className="relative max-w-4xl mx-auto">
          {/* Navigation Arrows */}
          <Button
            variant="outline"
            size="icon"
            onClick={goToPrevious}
            className="absolute left-0 top-1/2 -translate-y-1/2 z-10 bg-card hover:bg-muted border-border shadow-lg"
            aria-label="Previous testimonial"
            data-testid="button-previous-testimonial"
          >
            <ChevronLeft className="w-5 h-5" />
          </Button>

          <Button
            variant="outline"
            size="icon"
            onClick={goToNext}
            className="absolute right-0 top-1/2 -translate-y-1/2 z-10 bg-card hover:bg-muted border-border shadow-lg"
            aria-label="Next testimonial"
            data-testid="button-next-testimonial"
          >
            <ChevronRight className="w-5 h-5" />
          </Button>

          {/* Testimonial Display */}
          <div className="px-12 py-4">
            <div className="min-h-[280px] md:min-h-[320px] flex items-center">
              <AnimatePresence mode="wait">
                <motion.div
